defmodule SecureSessionPlug do
  import Plug.Conn

  @cookie_name "secure_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Lax",
    max_age: 3600
  ]

  def init(opts), do: opts

  def call(conn, opts) do
    secret_key = Keyword.fetch!(opts, :secret_key)
    
    case get_session_from_cookie(conn, secret_key) do
      {:ok, session} ->
        conn
        |> assign(:current_session, session)
        |> assign(:session_valid, true)
      
      {:error, _reason} ->
        conn
        |> assign(:current_session, nil)
        |> assign(:session_valid, false)
    end
  end

  def put_session(conn, session, secret_key) do
    encoded_session = SecureSessionManager.serialize_session(session, secret_key)
    
    put_resp_cookie(conn, @cookie_name, encoded_session, @cookie_opts)
  end

  def delete_session(conn) do
    delete_resp_cookie(conn, @cookie_name)
  end

  defp get_session_from_cookie(conn, secret_key) do
    case conn.cookies[@cookie_name] do
      nil -> {:error, :no_session}
      encoded_session -> SecureSessionManager.deserialize_session(encoded_session, secret_key)
    end
  end
end